var m = properties["Ratio"];
var p = properties["Power"];
var s = properties["Sync"];
var amount_eased = properties["Amount"][0];
var amount_linear = properties["Amount"][1];

var I = (s >= 0) ? (s - s % 1) : (s - s % 1 - (s % 1 != 0 ? 1 : 0));
var s_frac = s - I;

var EPSILON = 0.000001;
var m_is_zero = (m < EPSILON) ? 1 : 0;
var m_safe = m * (1 - m_is_zero) + EPSILON * m_is_zero;
var m1 = 1 - m;
var m1_is_zero = (m1 < EPSILON) ? 1 : 0;
var m1_safe = m1 * (1 - m1_is_zero) + EPSILON * m1_is_zero;

var x1 = s_frac / m_safe;
var v1 = (1 - pow(1 - x1, p)) * 0.5;
var x2 = (s_frac - m) / m1_safe;
var v2 = 0.5 + pow(x2, p) * 0.5;

var flag1 = (s_frac < m) ? 1 : 0;
var flag2 = (s_frac >= m) ? 1 : 0;
var E_shape = v1 * flag1 + v2 * flag2;

(I + E_shape) * amount_eased + s * amount_linear;
